import{_ as t,o as a,c as h,a0 as i}from"./chunks/framework.jwovEGr5.js";const l=JSON.parse('{"title":"Tài sản","description":"","frontmatter":{"title":"Tài sản","sidebar_position":5},"headers":[],"relativePath":"asset.md","filePath":"asset.md"}'),s={name:"asset.md"};function e(c,n,o,r,g,u){return a(),h("div",null,[...n[0]||(n[0]=[i('<h1 id="tai-san" tabindex="-1">Tài sản <a class="header-anchor" href="#tai-san" aria-label="Permalink to &quot;Tài sản&quot;">​</a></h1><p>Mô-đun Tài sản trong ABNERP cung cấp giải pháp toàn diện để quản lý vòng đời tài sản cố định của doanh nghiệp, từ khi mua sắm, đưa vào sử dụng, tính khấu hao, cho đến khi thanh lý. Mô-đun này tích hợp chặt chẽ với Kế toán và Mua hàng để đảm bảo tính chính xác và minh bạch.</p><h2 id="quan-ly-tai-san-co-đinh-fixed-asset-management" tabindex="-1">Quản lý tài sản cố định (Fixed Asset Management) <a class="header-anchor" href="#quan-ly-tai-san-co-đinh-fixed-asset-management" aria-label="Permalink to &quot;Quản lý tài sản cố định (Fixed Asset Management)&quot;">​</a></h2><p>Tài sản cố định bao gồm nhà xưởng, máy móc thiết bị, phương tiện vận tải và các tài sản khác có giá trị lớn và thời gian sử dụng dài. ABNERP cho phép quản lý chi tiết từng tài sản với các thông tin: mã tài sản, tên, chủng loại, ngày mua, nguyên giá, phòng ban sử dụng, và trạng thái. Hệ thống hỗ trợ gắn thẻ tài sản (mã vạch hoặc QR code) để thuận tiện cho việc kiểm kê. Bạn có thể tạo tài sản mới từ hóa đơn mua hàng hoặc nhập khẩu từ danh sách có sẵn.</p><h2 id="khau-hao-depreciation" tabindex="-1">Khấu hao (Depreciation) <a class="header-anchor" href="#khau-hao-depreciation" aria-label="Permalink to &quot;Khấu hao (Depreciation)&quot;">​</a></h2><p>ABNERP hỗ trợ nhiều phương pháp tính khấu hao: đường thẳng, số dư giảm dần, và theo sản lượng. Hệ thống tự động tạo các bút toán khấu hao hàng tháng dựa trên phương pháp đã chọn và thời gian sử dụng hữu ích của tài sản. Bạn có thể theo dõi giá trị còn lại, khấu hao lũy kế và giá trị thu hồi của từng tài sản tại bất kỳ thời điểm nào.</p><h2 id="di-chuyen-tai-san-asset-transfer" tabindex="-1">Di chuyển tài sản (Asset Transfer) <a class="header-anchor" href="#di-chuyen-tai-san-asset-transfer" aria-label="Permalink to &quot;Di chuyển tài sản (Asset Transfer)&quot;">​</a></h2><p>Khi tài sản được điều chuyển giữa các phòng ban, vị trí hoặc nhân viên quản lý, bạn có thể tạo phiếu di chuyển tài sản để ghi nhận sự thay đổi. Hệ thống lưu trữ lịch sử di chuyển đầy đủ, phục vụ cho việc kiểm tra nguồn gốc và trách nhiệm quản lý tài sản.</p><h2 id="bao-tri-tai-san-asset-maintenance" tabindex="-1">Bảo trì tài sản (Asset Maintenance) <a class="header-anchor" href="#bao-tri-tai-san-asset-maintenance" aria-label="Permalink to &quot;Bảo trì tài sản (Asset Maintenance)&quot;">​</a></h2><p>Bảo trì tài sản giúp kéo dài tuổi thọ và duy trì hiệu suất hoạt động của tài sản. Bạn có thể thiết lập lịch bảo trì định kỳ và ghi nhận chi phí bảo trì cho từng tài sản. Hệ thống cảnh báo khi đến hạn bảo trì và lưu trữ toàn bộ lịch sử bảo trì. Báo cáo tài sản cung cấp tổng quan về danh mục tài sản, giá trị, tình trạng sử dụng và biến động tài sản trong kỳ.</p>',10)])])}const p=t(s,[["render",e]]);export{l as __pageData,p as default};
